[
SRSReportParameterAttribute(classStr(ETGVendTransGroupingContract))
]
class ETGVendTransGroupingDP extends SRSReportDataProviderBase
{
    ETGVendTransGroupTmp vendTransGroupTmp;

}

Method.Source:
[SRSReportDataSetAttribute(tableStr(ETGVendTransGroupTmp))]
public ETGVendTransGroupTmp getETGVendTransGroupTmp()
{
    select vendTransGroupTmp;
    return vendTransGroupTmp;
}

public void processReport()
{
    ETGVendTransGroupingContract contract = this.parmDataContract() as ETGVendTransGroupingContract;

    if (!contract || !contract.validate())
    {
        return;
    }

    delete_from vendTransGroupTmp;

    this.createVendTransGroupData(contract.parmFromDate(), contract.parmToDate());
}

private void createVendTransGroupData(TransDate _fromDate, TransDate _toDate)
{
    VendTrans vendTransGrouping;
    VendTable vendTable;


    while select CurrencyCode, AccountNum from vendTransGrouping
        group by CurrencyCode, AccountNum
        where vendTransGrouping.TransDate <= _toDate
    {
        vendTransGroupTmp.clear();
        vendTransGroupTmp.AccountNum   = vendTransGrouping.AccountNum;
        vendTransGroupTmp.CurrencyCode = vendTransGrouping.CurrencyCode;


        vendTransGroupTmp.ETGVendName  = VendTable::find(vendTransGrouping.AccountNum).name();


        vendTransGroupTmp.OpeningBalance = this.getOpeningBalance(
                                                vendTransGrouping.AccountNum,
                                                vendTransGrouping.CurrencyCode,
                                                _fromDate);


        container periodAmounts = this.getPeriodAmounts(
                                        vendTransGrouping.AccountNum,
                                        vendTransGrouping.CurrencyCode,
                                        _fromDate,
                                        _toDate);

        vendTransGroupTmp.AmountDebit  = conPeek(periodAmounts, 1);
        vendTransGroupTmp.AmountCredit = conPeek(periodAmounts, 2);


        vendTransGroupTmp.SumAmount = vendTransGroupTmp.OpeningBalance +
                                      (vendTransGroupTmp.AmountDebit - vendTransGroupTmp.AmountCredit);


        if (vendTransGroupTmp.OpeningBalance != 0 ||
            vendTransGroupTmp.AmountDebit    != 0 ||
            vendTransGroupTmp.AmountCredit   != 0)
        {
            vendTransGroupTmp.insert();
        }
    }
}

private AmountCur getOpeningBalance(AccountNum _accountNum, CurrencyCode _currencyCode, TransDate _fromDate)
{
    VendTrans vendTransSum;

    select sum(AmountCur) from vendTransSum
        where vendTransSum.AccountNum   == _accountNum
           && vendTransSum.CurrencyCode == _currencyCode
           && vendTransSum.TransDate    <  _fromDate;

    return vendTransSum.AmountCur;
}

private container getPeriodAmounts(AccountNum _accountNum, CurrencyCode _currencyCode, TransDate _fromDate, TransDate _toDate)
{
    VendTrans vendTransSum;
    AmountCur totalDebit  = 0;
    AmountCur totalCredit = 0;


    select sum(AmountCur) from vendTransSum
        where vendTransSum.AccountNum   == _accountNum
           && vendTransSum.CurrencyCode == _currencyCode
           && vendTransSum.TransDate    >= _fromDate
           && vendTransSum.TransDate    <= _toDate
           && vendTransSum.AmountCur    >  0;

    totalDebit = vendTransSum.AmountCur;


    select sum(AmountCur) from vendTransSum
        where vendTransSum.AccountNum   == _accountNum
           && vendTransSum.CurrencyCode == _currencyCode
           && vendTransSum.TransDate    >= _fromDate
           && vendTransSum.TransDate    <= _toDate
           && vendTransSum.AmountCur    <  0;


    totalCredit = abs(vendTransSum.AmountCur);

    return [totalDebit, totalCredit];
}
